#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX 1005
#define MAX_K 1000000005

int compare(const void *a, const void *b) {
    return strcmp(*(char **)a, *(char **)b);
}

char **generate_subsequences(char *A, char *B, int n, int len, int *count) {
    char **subsequences = (char **)malloc(MAX_K * sizeof(char *));
    *count = 0;
    generate_subsequences_recursive(A, B, n, len, 0, 0, subsequences, count, (char *)malloc((len + 1) * sizeof(char)));
    free((char *)malloc((len + 1) * sizeof(char)));
    return subsequences;
}

void generate_subsequences_recursive(char *A, char *B, int n, int len, int i, int j, char **subsequences, int *count, char *current) {
    if (i == n || j == n) return;
    if (len == 0) {
        subsequences[(*count)++] = strdup(current);
        return;
    }
    if (A[i] == B[j]) {
        current[len - 1] = A[i];
        generate_subsequences_recursive(A, B, n, len - 1, i + 1, j + 1, subsequences, count, current);
    }
    generate_subsequences_recursive(A, B, n, len, i + 1, j, subsequences, count, current);
    generate_subsequences_recursive(A, B, n, len, i, j + 1, subsequences, count, current);
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);
    char A[MAX], B[MAX];
    scanf("%s %s", A, B);
    int len = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (A[i] == B[j]) {
                len = std::max(len, 1 + lcs(A, i + 1, B, j + 1));
            }
        }
    }
    int count;
    char **subsequences = generate_subsequences(A, B, n, len, &count);
    if (k > count) {
        printf("-1\n");
    } else {
        qsort(subsequences, count, sizeof(char *), compare);
        printf("%s\n", subsequences[k - 1]);
    }
    return 0;
}

