#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
using namespace std;

int lcs(string A, int i, string B, int j) {
    if (i == A.size() || j == B.size()) return 0;
    if (A[i] == B[j]) return 1 + lcs(A, i + 1, B, j + 1);
    return max(lcs(A, i + 1, B, j), lcs(A, i, B, j + 1));
}

vector<string> generate_subsequences(string A, string B, int n, int len) {
    vector<string> subsequences;
    generate_subsequences_recursive(A, B, n, len, 0, 0, "", subsequences);
    return subsequences;
}

void generate_subsequences_recursive(string A, string B, int n, int len, int i, int j, string current, vector<string> &subsequences) {
    if (i == n || j == n) return;
    if (len == 0) {
        subsequences.push_back(current);
        return;
    }
    if (A[i] == B[j]) {
        generate_subsequences_recursive(A, B, n, len - 1, i + 1, j + 1, current + A[i], subsequences);
    }
    generate_subsequences_recursive(A, B, n, len, i + 1, j, current, subsequences);
    generate_subsequences_recursive(A, B, n, len, i, j + 1, current, subsequences);
}

int main() {
    int n, k;
    cin >> n >> k;
    string A, B;
    cin >> A >> B;
    int len = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (A[i] == B[j]) {
                len = max(len, 1 + lcs(A, i + 1, B, j + 1));
            }
        }
    }
    vector<string> subsequences = generate_subsequences(A, B, n, len);
    if (k > subsequences.size()) {
        cout << -1 << endl;
    } else {
        sort(subsequences.begin(), subsequences.end());
        cout << subsequences[k - 1] << endl;
    }
    return 0;
}

