public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int k = scanner.nextInt();
        String A = scanner.next();
        String B = scanner.next();
        int len = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (A.charAt(i) == B.charAt(j)) {
                    len = Math.max(len, 1 + lcs(A, i + 1, B, j + 1));
                }
            }
        }
        String[] subsequences = generateSubsequences(A, B, n, len);
        if (k > subsequences.length) {
            System.out.println(-1);
        } else {
            Arrays.sort(subsequences);
            System.out.println(subsequences[k - 1]);
        }
    }

    public static int lcs(String A, int i, String B, int j) {
        if (i == A.length() || j == B.length()) return 0;
        if (A.charAt(i) == B.charAt(j)) return 1 + lcs(A, i + 1, B, j + 1);
        return Math.max(lcs(A, i + 1, B, j), lcs(A, i, B, j + 1));
    }

    public static String[] generateSubsequences(String A, String B, int n, int len) {
        String[] subsequences = new String[1000000];
        int count = 0;
        generateSubsequencesRecursive(A, B, n, len, 0, 0, "", subsequences, count);
        return Arrays.copyOf(subsequences, count);
    }

    public static void generateSubsequencesRecursive(String A, String B, int n, int len, int i, int j, String current, String[] subsequences, int count) {
        if (i == n || j == n) return;
        if (len == 0) {
            subsequences[count++] = current;
            return;
        }
        if (A.charAt(i) == B.charAt(j)) {
            generateSubsequencesRecursive(A, B, n, len - 1, i + 1, j + 1, current + A.charAt(i), subsequences, count);
        }
        generateSubsequencesRecursive(A, B, n, len, i + 1, j, current, subsequences, count);
        generateSubsequencesRecursive(A, B, n, len, i, j + 1, current, subsequences, count);
    }
}

